class StockSpanner {
public:
    StockSpanner() {
        prices.push_back(INT_MAX);
        days.push_back(0);
    }

    int next(int price) {
        int day = 1;
        while (prices.back() <= price) {
            day += days.back();
            prices.pop_back();
            days.pop_back();
        }
        prices.push_back(price);
        days.push_back(day);
        return day;
    }
private:
    vector<int> prices;
    vector<int> days;
};
